### Deobfuscated Code

```javascript
// Mathematical constants
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT2_HALF = 0.707;

// Physics and Simulation Configuration
const config = {
    attraction: 4000,     // Repulsion force between nodes
    frictionCoeff: 0.004, // (Unused directly in node physics, but defined)
    amplification: 0.92,  // Velocity damping multiplier (acts as friction)
    dispersal: 0.0003,    // Gravity/pull towards the center
    streamMax: 40,        // Max number of loose particles
    streamDecay: 0.04,    // Particle slowdown rate
    theta: 0.06           // Camera interpolation speed (easing)
};

// Nodes in the graph
let nodes = [
    { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Edges (Springs) connecting the nodes
let edges = [
    { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera / Viewport state
let currentView = { x: 400, y: 300, zoom: 1 };
let targetView  = { x: 400, y: 300, zoom: 1 };

let streamParticles = [];
let tickCount = 0;

// Helper: Get a node by its ID
function getNodeById(id) {
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// 1. Calculate physics for the nodes and springs
function updatePhysics() {
    // A. N-Body Repulsion (Nodes push away from each other)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let distSq = (dx * dx + dy * dy) || 1;

            // Inverse square law for repulsion
            let force = config.attraction / distSq; 
            let fx = (dx / Math.sqrt(distSq)) * force;
            let fy = (dy / Math.sqrt(distSq)) * force;

            nodes[i].vx += fx; nodes[i].vy += fy;
            nodes[j].vx -= fx; nodes[j].vy -= fy;
        }
    }

    // B. Hooke's Law (Springs pull connected nodes together)
    for (let i = 0; i < edges.length; i++) {
        let nodeA = getNodeById(edges[i].a);
        let nodeB = getNodeById(edges[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let distance = Math.sqrt(dx * dx + dy * dy) || 1;

        // Spring force = stiffness (k) * displacement from rest length
        let displacement = distance - edges[i].rest;
        let force = (edges[i].k) * displacement;

        let fx = (dx / distance) * force;
        let fy = (dy / distance) * force;

        nodeA.vx += fx; nodeA.vy += fy;
        nodeB.vx -= fx; nodeB.vy -= fy;
    }

    // C. Center Gravity & Velocity Damping (Friction)
    for (let i = 0; i < nodes.length; i++) {
        // Pull nodes gently back towards center (400, 300)
        nodes[i].vx += (400 - nodes[i].x) * config.dispersal;
        nodes[i].vy += (300 - nodes[i].y) * config.dispersal;

        // Apply friction
        nodes[i].vx *= config.amplification;
        nodes[i].vy *= config.amplification;

        // Apply velocity to position
        nodes[i].x += nodes[i].vx;
        nodes[i].y += nodes[i].vy;
    }
}

// 2. Spawn aesthetic loose particles ("streams")
function spawnStreamParticle() {
    if (streamParticles.length >= config.streamMax) return;

    // Pick a random node to emit a particle
    let node = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * TWO_PI;
    let speed = 0.3 + Math.random() * SQRT2_HALF;

    streamParticles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200, // Lives for a while
        size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT2_HALF
    });
}

// 3. Update loose particle positions
function updateStreamParticles() {
    for (let i = streamParticles.length - 1; i >= 0; i--) {
        let p = streamParticles[i];

        // Apply friction to particles
        p.vx *= (1 - config.streamDecay * 0.125);
        p.vy *= (1 - config.streamDecay * 0.125);

        p.x += p.vx;
        p.y += p.vy;
        p.age++;

        // Remove dead particles
        if (p.age > p.maxAge) {
            streamParticles.splice(i, 1);
        }
    }
}

// 4. Smoothly interpolate camera/viewport
function updateCamera() {
    currentView.x += (targetView.x - currentView.x) * config.theta;
    currentView.y += (targetView.y - currentView.y) * config.theta;
    currentView.zoom += (targetView.zoom - currentView.zoom) * config.theta;
}

// Main game/simulation loop
function mainLoop() {
    updatePhysics();
    updateStreamParticles();
    updateCamera();

    // Spawn a new particle every 3 ticks
    if (tickCount % 3 === 0) {
        spawnStreamParticle();
    }

    tickCount++;
}

// Run the simulation at roughly 60 FPS (every 16ms)
setInterval(mainLoop, 16);
```

### Explanation of what it does:

This code is the mathematical and logical backend for a **2D Force-Directed Graph Simulation**. It calculates the layout and visual effects of a network of nodes, likely intended to be drawn to an HTML5 `<canvas>`. 

Here are the specific mechanics it runs:

1. **The Graph Simulation (`updatePhysics`)**: 
   * It calculates physics for a network made of a "Hub" node and several satellite nodes (Alpha, Beta, etc.).
   * **Repulsion**: Every node acts like a magnet, pushing every other node away using an inverse-square calculation.
   * **Springs**: Edges act as rubber bands. If nodes are further apart than their `rest` distance, they are pulled together. If they are closer, they are pushed apart.
   * **Gravity & Friction**: It constantly pulls all nodes gently toward the center coordinates `(400, 300)` so they don't fly off the screen, and dampens their velocity so they eventually settle into a stable shape.
2. **Particle Effects (`spawnStreamParticle` & `updateStreamParticles`)**:
   * Purely for aesthetic purposes, it periodically spawns "stream" particles. 
   * Every 3 ticks, a particle shoots out from a random node in a random direction. These particles gradually slow down due to friction and eventually "die" and disappear once their `age` exceeds `maxAge`.
3. **Camera Smoothing (`updateCamera`)**:
   * It includes a basic ease-out algorithm (`current += (target - current) * ease`) to smoothly move a virtual camera or viewport when panning or zooming. 
4. **The Loop**: 
   * A `setInterval` runs the entire process every `16` milliseconds (~60 Frames Per Second), allowing the frontend to read the `nodes` and `streamParticles` arrays to draw a smooth, lively, floating graph.
